import { LABEL_ALIGNMENT } from '../constants.js';
import { useBoundaryLabels } from '../hooks/use-boundary-labels.js';
import { RangeLegendBoundaryLabel } from './RangeLegendBoundaryLabel/RangeLegendBoundaryLabel.js';
import { useScale } from '../context/RangeLegendScaleContext.js';
import { useLegendBoundaryLabelCollisionDetector } from '../hooks/use-legend-boundary-label-collision-detector.js';
import type { InternalRangeItem } from '../types/range-legend.internal.js';

interface RangeLegendBoundaryLabelsProps {
  items: InternalRangeItem[];
  minValue?: number;
  maxValue?: number;
}

export const RangeLegendBoundaryLabels = (
  props: RangeLegendBoundaryLabelsProps,
) => {
  const { maxValue, minValue, items } = props;

  const { scale } = useScale();

  const [rangeStartPosition, rangeEndPosition] = scale.range();

  const { firstLabel, lastLabel } = useBoundaryLabels(
    items,
    rangeStartPosition,
    rangeEndPosition,
    minValue,
    maxValue,
  );

  const { startLabel, endLabel } = useLegendBoundaryLabelCollisionDetector(
    firstLabel,
    lastLabel,
  );

  return (
    <g role="list" aria-label={`Boundaries ${firstLabel} to ${lastLabel}`}>
      <RangeLegendBoundaryLabel
        alignment={LABEL_ALIGNMENT.Start}
        startPosition={rangeStartPosition}
        endPosition={rangeEndPosition}
        text={startLabel}
        data-first-label="true"
      />
      <RangeLegendBoundaryLabel
        alignment={LABEL_ALIGNMENT.End}
        startPosition={rangeStartPosition}
        endPosition={rangeEndPosition}
        text={endLabel}
        data-last-label="true"
      />
    </g>
  );
};
